        print(f"Processing task_id={task_id}, task_type={task_type}, payload={payload}")
        duration = payload.get("duration", 1)
        try:
            duration = max(0, float(duration))
        except (TypeError, ValueError):
            duration = 1
        time.sleep(duration)
        print(f"Completed task_id={task_id}")

